#include <stdio.h>
#include <stdlib.h>

// Structure to represent an interval
typedef struct {
    int start;
    int end;
} Interval;

// Comparison function for sorting intervals based on end points
int compareIntervals(const void *a, const void *b) {
    Interval *x = (Interval *)a;
    Interval *y = (Interval *)b;
    return x->end - y->end;
}

int findMinimumRemovals(Interval *intervals, int n) {
    if (n == 0) return 0;

    // Sort intervals based on end points
    qsort(intervals, n, sizeof(Interval), compareIntervals);

    int removals = 0;
    int end = intervals[0].end;

    for (int i = 1; i < n; i++) {
        if (intervals[i].start < end) {
            // Overlap: remove interval
            removals++;
        } else {
            // No overlap: keep interval & update
            end = intervals[i].end;
        }
    }

    return removals;
}

int main() {
    int t;
    scanf("%d", &t);

    while (t--) {
        int n;
        scanf("%d", &n);

        Interval *intervals = (Interval *)malloc(n * sizeof(Interval));

        for (int i = 0; i < n; i++) {
            scanf("%d %d", &intervals[i].start, &intervals[i].end);
        }

        printf("%d\n", findMinimumRemovals(intervals, n));

        free(intervals);
    }

    return 0;
}

