#include <algorithm>
using namespace std;

struct Interval {
    int start;
    int end;
};

bool compareIntervals(const Interval &a, const Interval &b) {
    return a.end < b.end;
}

int findMinimumRemovals(vector<Interval> &intervals) {
    if (intervals.empty()) return 0;

    // Sort intervals based on end points
    sort(intervals.begin(), intervals.end(), compareIntervals);

    int removals = 0;
    int end = intervals[0].end;

    for (int i = 1; i < intervals.size(); i++) {
        if (intervals[i].start < end) {
            // Overlap: remove interval
            removals++;
        } else {
            // No overlap: keep interval & update
            end = intervals[i].end;
        }
    }

    return removals;
}

int main() {
    int t;
    cin >> t;

