import java.util.Arrays;
import java.util.Scanner;

public class Main {
    static class Interval implements Comparable<Interval> {
        int start;
        int end;

        public Interval(int start, int end) {
            this.start = start;
            this.end = end;
        }

        @Override
        public int compareTo(Interval other) {
            return Integer.compare(this.end, other.end);
        }
    }

    public static int findMinimumRemovals(Interval[] intervals) {
        if (intervals.length == 0) return 0;

        // Sort intervals based on end points
        Arrays.sort(intervals);

        int removals = 0;
        int end = intervals[0].end;

        for (int i = 1; i < intervals.length; i++) {
            if (intervals[i].start < end) {
                // Overlap: remove interval
                removals++;
            } else {
                // No overlap: keep interval & update
                end = intervals[i].end;
            }
        }

        return removals;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt();

        while (t-- > 0) {
            int n = scanner.nextInt();
            Interval[] intervals = new Interval[n];

            for (int i = 0; i < n; i++) {
                intervals[i] = new Interval(scanner.nextInt(), scanner.nextInt());
            }

            System.out.println(findMinimumRemovals(intervals));
        }
    }
}

